/**
 * Map an array with an async function sequentially.
 * @param {unknown[]} items
 * @param {(item: unknown, index: number) => Promise<unknown>} mapper
 * @returns {Promise<unknown[]>}
 * @throws {TypeError} When items is not an array
 */
export async function mapAsync(items, mapper) {
  if (!Array.isArray(items)) {
    throw new TypeError('items must be an array');
  }
  const results = [];
  for (let index = 0; index < items.length; index += 1) {
    results.push(await mapper(items[index], index));
  }
  return results;
}
